local function uC(oq)
	return debug.traceback(oq)
end
local function up(uL, eu)
	return function(aU)
		if typeof(aU) == "function" then
			local nx, dx = xpcall(function()
				return aU(eu)
			end, uC)
			if not nx then
				eu._errorReporter.reportReducerError(
					eu:getState(),
					aU,
					{ message = "Caught error in thunk", thrownValue = dx }
				)
				return nil
			end
			return dx
		end
		return uL(aU)
	end
end
return up
